  CouplingInfo make_coupling_info_map(const long long int l_max) {
    const long long int lm_size = (l_max + 1) * (l_max + 1);
    CouplingInfo result(lm_size);
    for(auto [lm1, lm2, lm, coeff] : edmond_coeffs){
      if(lm < lm_size && lm1 < lm_size && lm2 < lm_size){
	result[lm].push_back(std::make_tuple(coeff, lm1, lm2));
      }
    }
    return result;
  }

  CouplingInfo make_coupling_info_map(const long long int l_max, const std::vector<long long int> &nonzero_pos) {
    const long long int lm_size = (l_max + 1) * (l_max + 1);
    const std::unordered_set<long long int> nonzero_pos_set(nonzero_pos.begin(), nonzero_pos.end());
    CouplingInfo result(lm_size);
    for(auto [lm1, lm2, lm, coeff] : edmond_coeffs){
      if(lm < lm_size && lm1 < lm_size && lm2 < lm_size && nonzero_pos_set.contains(lm1)){
	result[lm].push_back(std::make_tuple(coeff, lm1, lm2));
      }
    }
    return result;
  }  

